section.script:
document.addEventListener('DOMContentLoaded', function() {
    var heroCarousel = document.getElementById('unitradeHeroCarousel');
    if (heroCarousel) {
        // Initial trigger
        triggerTextAnimation(0);

        heroCarousel.addEventListener('slide.bs.carousel', function (e) {
            // Update indicator
            var currentSpan = document.getElementById('heroSlideCurrent');
            if (currentSpan) {
                currentSpan.textContent = e.to + 1;
            }

            // Handle Text Transitions
            var allGroups = document.querySelectorAll('.slide-text-group');
            allGroups.forEach(function(group) {
                group.classList.remove('tw-opacity-100');
                group.classList.add('tw-opacity-0', 'tw-pointer-events-none');

                var anims = group.querySelectorAll('.slide-anim');
                anims.forEach(function(el) {
                    el.style.opacity = '0';
                    el.style.transform = 'translateX(-30px)';
                });
            });

            var targetGroup = document.getElementById('textGroup-' + e.to);
            if (targetGroup) {
                targetGroup.classList.remove('tw-opacity-0', 'tw-pointer-events-none');
                targetGroup.classList.add('tw-opacity-100');
                triggerTextAnimation(e.to);
            }
        });
    }

    function triggerTextAnimation(index) {
        var group = document.getElementById('textGroup-' + index);
        if (group) {
            setTimeout(function() {
                var anims = group.querySelectorAll('.slide-anim');
                anims.forEach(function(el) {
                    el.style.opacity = '1';
                    el.style.transform = 'translateX(0)';
                });
            }, 50);
        }
    }
});
